#!/usr/bin/env python3
"""Merge user data from three sources with different schemas."""
import json
import csv
import pandas as pd

# Field name -> unified name mapping
USER_ID_KEYS = ("user_id", "id", "userId")
EMAIL_KEYS = ("email", "email_address")
NAME_KEYS = ("full_name", "name", "userName")
DATE_KEYS = ("registration_date", "created_at", "joined")
STATUS_KEYS = ("status", "is_active", "active")


def pick(record, keys):
    for k in keys:
        if k in record and record[k] is not None:
            return record[k]
    return None


def to_date(value):
    if value is None:
        return None
    return pd.to_datetime(str(value)).strftime("%Y-%m-%d")


def to_status(value):
    if value is None:
        return None
    if isinstance(value, bool):
        return "active" if value else "inactive"
    s = str(value).strip()
    if s.lower() in ("true", "false"):
        return "active" if s.lower() == "true" else "inactive"
    return s


def normalize(record):
    return {
        "user_id": int(pick(record, USER_ID_KEYS)),
        "name": pick(record, NAME_KEYS),
        "email": pick(record, EMAIL_KEYS),
        "created_date": to_date(pick(record, DATE_KEYS)),
        "status": to_status(pick(record, STATUS_KEYS)),
    }


def load_source_a():
    with open("/data/source_a/users.json") as f:
        return [normalize(r) for r in json.load(f)]


def load_source_b():
    out = []
    with open("/data/source_b/users.csv", newline="") as f:
        for r in csv.DictReader(f):
            out.append(normalize(r))
    return out


def load_source_c():
    df = pd.read_parquet("/data/source_c/users.parquet")
    return [normalize(r) for r in df.to_dict("records")]


# Priority: source_a > source_b > source_c
SOURCES = [("source_a", load_source_a()),
           ("source_b", load_source_b()),
           ("source_c", load_source_c())]
PRIORITY = ["source_a", "source_b", "source_c"]
CONFLICT_FIELDS = ["name", "email", "created_date", "status"]

# Index records per user_id per source
by_user = {}
for sname, records in SOURCES:
    for rec in records:
        uid = rec["user_id"]
        by_user.setdefault(uid, {})[sname] = rec

merged_rows = []
conflicts = []

for uid in sorted(by_user):
    per_source = by_user[uid]
    row = {"user_id": uid}
    for field in CONFLICT_FIELDS:
        # Values present for this field, in priority order
        present = {s: per_source[s][field]
                   for s in PRIORITY
                   if s in per_source and per_source[s][field] is not None}
        selected = None
        for s in PRIORITY:
            if s in present:
                selected = present[s]
                break
        row[field] = selected
        # Conflict if user in multiple sources with differing values
        distinct = set(present.values())
        if len(distinct) > 1:
            conflicts.append({
                "user_id": uid,
                "field": field,
                "values": {s: present[s] for s in PRIORITY if s in present},
                "selected": selected,
            })
    merged_rows.append(row)

merged_df = pd.DataFrame(merged_rows,
                         columns=["user_id", "name", "email", "created_date", "status"])
merged_df["user_id"] = merged_df["user_id"].astype("int64")
for col in ["name", "email", "created_date", "status"]:
    merged_df[col] = merged_df[col].astype("object")
merged_df.to_parquet("/app/merged_users.parquet", index=False)

report = {"total_conflicts": len(conflicts), "conflicts": conflicts}
with open("/app/conflicts.json", "w") as f:
    json.dump(report, f, indent=2)

print(merged_df.to_string(index=False))
print(merged_df.dtypes)
print("total_conflicts:", len(conflicts))
"""end"""

